// [NODO: Set HTML - Versión Unificada y Priorizada]
// MODO: Run Once for All Items

const allItems = $input.all();

// Si no hay ítems de entrada, retornar vacío o error básico
if (allItems.length === 0) {
    let type = "General";
    try { type = $("Credentials Loop").first().json["type"] || "General"; } catch(e) {}
    if (['Bi-hourly', 'Hourly', 'Nightly'].includes(type)) return []; 
    return { json: { htmlContent: "<p>No hay datos que procesar.</p>" } };
}

const allQueries = allItems.map(item => item.json);

// 1. SEPARAR ÍTEMS: Errores vs Exitosos
const errorItems = allQueries.filter(q => q._isError === true);
const successItems = allQueries.filter(q => q._isError !== true);

// 2. ESTILOS CENTRALIZADOS
const styles = {
    container: 'font-family:sans-serif;font-size:13px;color:#000;',
    h1: 'font-size:20px;margin:0;',
    h2: 'font-size:13px;margin:0 0 15px 0;text-transform:uppercase;font-weight:normal;',
    h3: 'font-size:15px;font-weight:bold;margin:15px 0 5px 0;',
    errorTitle: 'font-size:15px;font-weight:bold;margin:15px 0 5px 0;color:#d9534f;', // Rojo para errores
    table: 'width:100%;border-collapse:collapse;',
    pre: 'font-family:monospace;font-size:11px;background:#f4f4f4;padding:8px;border:1px solid #ccc;',
    notice: 'font-size:11px;font-style:italic;',
    footer: 'margin-top:15px;font-size:12px;border-top:1px solid #eee;'
};

// 3. OBTENER METADATOS (Tipo y Frecuencia)
let reportType = "General";
try { reportType = $("Credentials Loop").first().json["type"] || "General"; } catch(e) {}

let frequency = "General";
if (reportType === "Daily") frequency = "Diaria";
else if (reportType === "Four-hourly") frequency = "cada 4 horas";
else if (reportType === "Hourly") frequency = "cada 1 hora";
else if (reportType === "Bi-hourly") frequency = "cada 2 horas";

// 4. PROCESAR TABLAS (Solo de los ítems exitosos)
let validHtmlParts = []; 
let hiddenQueriesCount = 0;

for (const item of successItems) {
    const results = item.result;

    // Validar si el resultado exitoso está vacío
    let isEmpty = false;
    if (!results || (Array.isArray(results) && results.length === 0)) {
        isEmpty = true;
    } else if (Array.isArray(results) && results.length === 1) {
        const firstItem = results[0];
        if (firstItem === null || (typeof firstItem === 'object' && Object.keys(firstItem).length === 0)) {
            isEmpty = true;
        }
    }

    if (isEmpty) {
        hiddenQueriesCount++; 
        continue; 
    }

    let itemHtml = `<h3 style="${styles.h3}">Punto ${item.queryId}: ${item.description || "Sin descripción"}</h3>`;

    const MAX_ROWS = 150; 
    const MAX_COLS = 10;
    let data = results.length > MAX_ROWS ? results.slice(0, MAX_ROWS) : results;
    let fullHeaders = Object.keys(data[0] || {});
    let headers = fullHeaders.length > MAX_COLS ? fullHeaders.slice(0, MAX_COLS) : fullHeaders;

    itemHtml += `<table border="1" cellpadding="4" cellspacing="0" style="${styles.table}"><thead><tr bgcolor="#f2f2f2">`;
    for (const h of headers) itemHtml += `<th align="left">${h}</th>`;
    itemHtml += "</tr></thead><tbody>";

    for (const row of data) {
        itemHtml += "<tr>";
        for (const h of headers) {
            const val = row[h];
            const cleanVal = (val === null || val === undefined) ? "" : String(val).replace(/</g, '&lt;').replace(/>/g, '&gt;');
            itemHtml += `<td>${cleanVal}</td>`;
        }
        itemHtml += "</tr>";
    }
    itemHtml += "</tbody></table>";

    if (results.length > MAX_ROWS || fullHeaders.length > MAX_COLS) {
        itemHtml += `<p style="${styles.notice}">(Vista limitada: ${results.length > MAX_ROWS ? MAX_ROWS + ' filas ' : ''}${fullHeaders.length > MAX_COLS ? MAX_COLS + ' columnas' : ''})</p>`;
    }

    if (String(item.pattern || "0").trim() === '2') {
        const combinedQueryText = `-- SELECT\n${item.revisionQuery || ""}\n\n-- UPDATE\n${item.correctionQuery || ""}`;
        itemHtml += `<p><b>Cargar ticket con:</b></p><pre style="${styles.pre}">${combinedQueryText}</pre>`;
    }

    validHtmlParts.push(itemHtml);
}

// 5. LÓGICA ANTI-SPAM DEFINITIVA
// Si no hay tablas para mostrar Y no hay errores, abortar silenciosamente (si aplica la frecuencia)
if (validHtmlParts.length === 0 && errorItems.length === 0) {
    if (['Bi-hourly', 'Hourly', 'Nightly'].includes(reportType)) return [];
}

// 6. ENSAMBLAR EL REPORTE HTML (Errores ARRIBA, Tablas ABAJO)
let finalHtml = `<div style="${styles.container}">`;

if (reportType === 'Daily') {
  const now = new Date();
  const dateStr = now.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
  const dateFormatted = dateStr.charAt(0).toUpperCase() + dateStr.slice(1);
  finalHtml += `<h1 style="${styles.h1}">${dateFormatted}</h1>`;
}

finalHtml += `<h2 style="${styles.h2}">Resultados de la Revisión de Entornos ${frequency}</h2>`;

// 6A. SECCIÓN DE ERRORES (Aparece primero)
if (errorItems.length > 0) {
    finalHtml += `<h3 style="${styles.errorTitle}">Queries con error</h3><ul>`;
    for (const e of errorItems) {
        const desc = e.description || 'Sin descripción';
        const errMsg = (e._errorMessage || 'Error desconocido').toString().slice(0, 300);
        finalHtml += `<li><b>⚠️ Punto ${e.queryId}:</b> ${desc} — ${errMsg}</li>`;
    }
    finalHtml += `</ul><hr size="1" color="#eee">`;
}

// 6B. SECCIÓN DE RESULTADOS (Tablas)
if (validHtmlParts.length === 0) {
    finalHtml += `<div style="${styles.footer}">✅ Sin novedades operativas.</div>`;
} else {
    finalHtml += validHtmlParts.join('<hr size="1" color="#eee">');
    if (hiddenQueriesCount > 0) {
        finalHtml += `<div style="${styles.footer}">El resto de los puntos no dieron resultados.</div>`;
    }
}

finalHtml += `</div>`;

return { 
    json: { htmlContent: finalHtml },
    pairedItem: allItems.length > 0 ? allItems[0].pairedItem : undefined
};

