}

return items;

const results = $input.all();
const errorMsg = typeof results[0]?.json?.error === 'string' ? results[0].json.error : null;
const hasError = !!errorMsg;

// Unificamos el objeto de fecha
const now = new Date();
const start = $('Audit Start').item?.json?.audit_startTime || $('Audit Start').first().json.audit_startTime;

const e = $('Credentials Loop').item?.json || {};
const q = $('Query Loop').item?.json || {};

// Asumimos que estas variables se calculan aquí en base a los resultados si no hay error
const realResultsCount = hasError ? 0 : results.length;
const sizeInBytes = hasError ? 0 : JSON.stringify(results).length; // Ejemplo de cálculo si no venía definido

return [{
  json: {
    query:             q.queryId     || 'N/A',
    pais:              e.country     || 'Desconocido',
    entorno:           e.entorno     || 'Desconocido',
    frecuencia:        q.type        || 'N/A',
    description:       q.description || 'Sin descripción',
    aplicacion:        q.application || 'N/A',
    tiempo:            +((now - start) / 1000).toFixed(2), // '+' reemplaza a parseFloat
    peso:              +((sizeInBytes / 1024).toFixed(2)),
    filas_encontradas: realResultsCount,
    timestamp_tz:      now.toISOString().split('.')[0].replace('T', ' ') + '+00',
    fecha_real:        now.toLocaleDateString("en-CA", { timeZone: "America/Argentina/Buenos_Aires" }),
    hora_limpia:       now.toLocaleTimeString("en-GB", { timeZone: "America/Argentina/Buenos_Aires" }),
    status:            !hasError,
    error_message:     errorMsg || null
  }
}];
